builder.Services.AddOpenTelemetry()
    .WithTracing(t => t
        .AddAspNetCoreInstrumentation()
        .AddHttpClientInstrumentation()
        .AddEntityFrameworkCoreInstrumentation()
        .AddSource("MyApp.*")
        .AddOtlpExporter(o => o.Endpoint = new Uri("http://otel-collector:4317")))
    .WithMetrics(m => m
        .AddAspNetCoreInstrumentation()
        .AddRuntimeInstrumentation()
        .AddMeter("MyApp.*")
        .AddPrometheusExporter())
    .WithLogging(l => l.AddOtlpExporter());

// Custom instrumentation
private static readonly ActivitySource _tracer = new("MyApp.Orders");
private static readonly Meter _meter = new("MyApp.Orders");
private static readonly Counter<long> _ordersCreated =
    _meter.CreateCounter<long>("orders.created");

public async Task<Order> CreateOrderAsync(CreateOrderDto dto, CancellationToken ct)
{
    using var activity = _tracer.StartActivity("CreateOrder");
    activity?.SetTag("order.customerId", dto.CustomerId);
    var order = await _repo.CreateAsync(dto, ct);
    activity?.SetTag("order.id", order.Id);
    _ordersCreated.Add(1, new TagList { { "currency", dto.Currency } });
    return order;
}
